import React, { useState, useEffect } from 'react';
import { Link, useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import styles from '../pages/PageStyle2.module.css';


function CustomerEditPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  return (
    <EmployeeLayout title="Dashboard">
      <div>
        <h1>Edit Customer {id}</h1>
        <p>This is where you would edit customer details.</p>
        <button onClick={() => navigate('/cust')}>Back to Customer List</button>
      </div>
      {error && <p className={styles.error}>{error}</p>}
      <div className={styles.statsGrid}>
        <Link to="/releasescust" className={styles.statCard}><h2>{stats.releasesThisWeek}</h2><p>Releases This Week</p></Link>
        <Link to="/releasescust" className={styles.statCard}><h2>{stats.releasesNextWeek}</h2><p>Releases Next Week</p></Link> 
        <Link to="/pullscust" className={styles.statCard}><h2>{stats.outstandingPulls}</h2><p>All Outstanding Pulls</p></Link> 
        <Link to="/pullscust" className={styles.statCard}><h2>{stats.upcomingPulls}</h2><p>All Upcoming Pulls</p></Link>
      </div>
    </EmployeeLayout>
  );
}

export default CustomerEditPage;
